// 格式化查询结果为Telegram消息
const inputData = $input.all();

console.log('=== 格式化查询结果 ===');
console.log('输入数据类型:', typeof inputData);
console.log('输入数据长度:', inputData.length);

// 检查输入数据
if (!inputData || !Array.isArray(inputData) || inputData.length === 0) {
  return {
    success: false,
    error: '输入数据格式不正确',
    debugInfo: {
      inputType: typeof inputData,
      isArray: Array.isArray(inputData),
      length: inputData ? inputData.length : 'undefined'
    }
  };
}

// 获取查询结果数据
let queryResult = inputData[0].json;

console.log('查询结果数据类型:', typeof queryResult);
console.log('查询结果是否为数组:', Array.isArray(queryResult));

// 如果查询结果是数组，取第一个元素
if (Array.isArray(queryResult)) {
  queryResult = queryResult[0];
  console.log('查询结果是数组，取第一个元素');
}

console.log('处理后的查询结果:', queryResult);

// 检查查询结果是否包含必要字段
if (!queryResult || !queryResult.id) {
  return {
    success: false,
    error: '查询结果格式不正确，缺少必要字段',
    debugInfo: {
      hasId: !!queryResult?.id,
      queryResultKeys: queryResult ? Object.keys(queryResult) : 'undefined'
    }
  };
}

// 格式化查询结果为可读消息
function formatQueryResult(result) {
  const {
    id,
    uid,
    merchant_id,
    game_id,
    game_code,
    result: gameResult,
    currency,
    amount,
    pay_out,
    multiplier,
    balance,
    created_at,
    updated_at
  } = result;

  // 解析游戏详情
  let gameDetail = '';
  try {
    if (result.detail) {
      const detail = JSON.parse(result.detail);
      if (detail.recall) {
        const recall = JSON.parse(detail.recall);
        gameDetail = `\n🎮 游戏详情:\n- 倍数序列: ${recall.multis ? recall.multis.slice(0, 5).join(', ') + '...' : 'N/A'}\n- 种子: ${detail.seed?.seed || 'N/A'}`;
      }
    }
  } catch (e) {
    console.log('解析游戏详情失败:', e.message);
  }

  // 格式化消息
  const message = `🔍 **查询结果**

📋 **基本信息:**
- 投注ID: \`${id}\`
- 用户UID: \`${uid}\`
- 商户ID: \`${merchant_id}\`
- 游戏ID: \`${game_id}\`

🎯 **游戏信息:**
- 游戏代码: \`${game_code}\`
- 游戏结果: ${gameResult === '1' ? '✅ 获胜' : '❌ 失败'}
- 倍数: \`${multiplier}x\`

💰 **金额信息:**
- 投注金额: \`${amount} ${currency}\`
- 派奖金额: \`${pay_out} ${currency}\`
- 余额: \`${balance} ${currency}\`

⏰ **时间信息:**
- 创建时间: \`${created_at}\`
- 更新时间: \`${updated_at}\`${gameDetail}

✅ 查询完成，数据已导出为CSV文件`;

  return message;
}

// 生成格式化消息
const formattedMessage = formatQueryResult(queryResult);

console.log('格式化消息长度:', formattedMessage.length);

// 返回结果
const result = {
  success: true,
  message: formattedMessage,
  queryData: queryResult,
  summary: {
    betId: queryResult.id,
    uid: queryResult.uid,
    merchantId: queryResult.merchant_id,
    gameCode: queryResult.game_code,
    result: queryResult.result === '1' ? '获胜' : '失败',
    amount: queryResult.amount,
    currency: queryResult.currency,
    payout: queryResult.pay_out,
    multiplier: queryResult.multiplier
  }
};

console.log('格式化完成:', result.summary);
return result;

// 准备发送到Telegram的数据
const inputData = $input.all();

console.log('=== 准备Telegram数据 ===');
console.log('输入数据类型:', typeof inputData);
console.log('输入数据长度:', inputData.length);

// 检查输入数据
if (!inputData || !Array.isArray(inputData) || inputData.length < 2) {
  return {
    success: false,
    error: '输入数据格式不正确，需要格式化消息和导出结果',
    debugInfo: {
      inputType: typeof inputData,
      isArray: Array.isArray(inputData),
      length: inputData ? inputData.length : 'undefined'
    }
  };
}

// 获取格式化消息和导出结果
let formattedMessage = inputData[0].json;
let exportResult = inputData[1].json;

console.log('格式化消息类型:', typeof formattedMessage);
console.log('导出结果类型:', typeof exportResult);

// 如果数据是数组，取第一个元素
if (Array.isArray(formattedMessage)) {
  formattedMessage = formattedMessage[0];
}
if (Array.isArray(exportResult)) {
  exportResult = exportResult[0];
}

console.log('处理后的格式化消息:', formattedMessage);
console.log('处理后的导出结果:', exportResult);

// 检查必要字段
if (!formattedMessage || !formattedMessage.message) {
  return {
    success: false,
    error: '格式化消息数据不正确',
    debugInfo: {
      hasMessage: !!formattedMessage?.message,
      formattedMessageKeys: formattedMessage ? Object.keys(formattedMessage) : 'undefined'
    }
  };
}

if (!exportResult || !exportResult.data || !exportResult.data.downloadUrls) {
  return {
    success: false,
    error: '导出结果数据不正确',
    debugInfo: {
      hasData: !!exportResult?.data,
      hasDownloadUrls: !!exportResult?.data?.downloadUrls,
      exportResultKeys: exportResult ? Object.keys(exportResult) : 'undefined'
    }
  };
}

// 获取下载URL
const downloadUrl = exportResult.data.downloadUrls[0];
if (!downloadUrl) {
  return {
    success: false,
    error: '没有找到下载链接',
    debugInfo: {
      downloadUrls: exportResult.data.downloadUrls
    }
  };
}

// 构建完整的文件URL
const baseUrl = 'https://ebooks-life-point-interactions.trycloudflare.com';
const fullFileUrl = baseUrl + downloadUrl.url;

console.log('完整文件URL:', fullFileUrl);

// 准备Telegram发送数据
const telegramData = {
  // Telegram配置 - 这些值需要从环境变量或配置中获取
  telegramBotToken: 'YOUR_BOT_TOKEN', // 需要替换为实际的Bot Token
  chatId: -1003129050838, // 从查询结果中获取的chatId

  // 消息内容
  message: formattedMessage.message,

  // 文件信息
  fileUrl: fullFileUrl,
  fileName: downloadUrl.filename,
  fileSize: downloadUrl.size,
  fileRows: downloadUrl.rows,

  // 查询摘要
  summary: formattedMessage.summary,

  // 导出信息
  exportInfo: {
    queryId: exportResult.data.queryId,
    format: exportResult.data.format,
    totalRows: exportResult.data.totalRows,
    files: exportResult.data.files
  }
};

console.log('准备完成的Telegram数据:', {
  messageLength: telegramData.message.length,
  fileName: telegramData.fileName,
  fileSize: telegramData.fileSize,
  fileRows: telegramData.fileRows
});

// 返回结果
const result = {
  success: true,
  telegramData: telegramData,
  message: `准备完成！将发送${telegramData.fileRows}行数据到Telegram群组`,
  debugInfo: {
    messageLength: telegramData.message.length,
    fileName: telegramData.fileName,
    fileSize: telegramData.fileSize,
    fileRows: telegramData.fileRows,
    downloadUrl: fullFileUrl
  }
};

console.log('数据准备完成:', result.message);
return result;

